import React, { useState, useEffect } from 'react';
import './FloatingNewsletter.css';
import { FaCheck } from 'react-icons/fa';

export default function FloatingNewsletter() {
  const [subscribed, setSubscribed] = useState(false);
  const [visible, setVisible] = useState(false);

  const BASE_URL = 'https://sofia-backend-9l77.onrender.com';

  useEffect(() => {
    setTimeout(() => setVisible(true), 300); // delay for fade-in effect
  }, []);

  const handleSubscribe = async () => {
    try {
      await fetch(`${BASE_URL}/subscribe`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: 'anonymous@newsletter.bali' }), // demo email
      });
      setSubscribed(true);
    } catch (err) {
      console.error('Subscription failed', err);
    }
  };

  if (!visible) return null;

  return (
    <div className={`floating-newsletter ${visible ? 'fade-in' : ''}`}>
      {!subscribed ? (
        <button className="check-button" onClick={handleSubscribe}>
          Join Newsletter 💌
        </button>
      ) : (
        <div className="check-confirmation">
          <FaCheck className="check-icon" />
        </div>
      )}
    </div>
  );
}
